"""Markdown body parsing and section-level editing helpers."""

from __future__ import annotations

from dataclasses import dataclass, replace
import difflib
import re


HEADING_RE = re.compile(r"^##\s+(.+?)\s*$")
TITLE_RE = re.compile(r"^#\s+(.+?)\s*$")
_FENCE_RE = re.compile(r"^\s*(```|~~~)")
_PREAMBLE = "_preamble"


class BodyValidationError(ValueError):
    pass


class SectionNotFound(ValueError):
    pass


class SectionExists(ValueError):
    pass


class InvalidPosition(ValueError):
    pass


@dataclass(frozen=True)
class Section:
    name: str
    heading: str
    content: str

    @property
    def raw(self) -> str:
        return f"{self.heading}{self.content}"


@dataclass(frozen=True)
class ParsedBody:
    title: str | None
    goal_first_paragraph: str | None
    preamble: str
    sections: list[Section]


def parse(body: str) -> ParsedBody:
    """Parse markdown into title, preamble, and top-level ## sections.

    This function is deliberately lenient and never raises for malformed body
    text. Validation for writes is handled by ``validate_for_write``.
    """

    try:
        text = "" if body is None else str(body)
        boundaries = _section_boundaries(text)
        if not boundaries:
            preamble = text
            sections: list[Section] = []
        else:
            preamble = text[: boundaries[0][0]]
            sections = []
            for index, (start, end, name, heading) in enumerate(boundaries):
                next_start = boundaries[index + 1][0] if index + 1 < len(boundaries) else len(text)
                sections.append(Section(name=name, heading=heading, content=text[end:next_start]))
        return ParsedBody(
            title=_extract_title(preamble),
            goal_first_paragraph=_extract_goal(sections),
            preamble=preamble,
            sections=sections,
        )
    except Exception:
        return ParsedBody(title=None, goal_first_paragraph=None, preamble="" if body is None else str(body), sections=[])


def serialize(parsed: ParsedBody) -> str:
    return parsed.preamble + "".join(section.raw for section in parsed.sections)


def validate_for_write(parsed: ParsedBody) -> None:
    if not parsed.title:
        raise BodyValidationError("body_missing_required_section: title")
    if not parsed.goal_first_paragraph:
        raise BodyValidationError("body_missing_required_section: goal")


def outline(parsed: ParsedBody) -> dict[str, object]:
    body_text = serialize(parsed)
    return {
        "title": parsed.title,
        "goal": parsed.goal_first_paragraph,
        "total_lines": _line_count(body_text),
        "sections": [
            {
                "name": section.name,
                "line_count": _line_count(section.raw),
            }
            for section in parsed.sections
        ],
    }


def replace_section(parsed: ParsedBody, name: str, content: str) -> ParsedBody:
    if name == _PREAMBLE:
        return parse(str(content) + "".join(section.raw for section in parsed.sections))
    index = _section_index(parsed, name)
    sections = list(parsed.sections)
    sections[index] = replace(sections[index], content=str(content))
    return parse(parsed.preamble + "".join(section.raw for section in sections))


def append_to_section(parsed: ParsedBody, name: str, content: str) -> ParsedBody:
    if name == _PREAMBLE:
        return replace_section(parsed, name, parsed.preamble + str(content))
    index = _section_index(parsed, name)
    sections = list(parsed.sections)
    sections[index] = replace(sections[index], content=sections[index].content + str(content))
    return parse(parsed.preamble + "".join(section.raw for section in sections))


def add_section(parsed: ParsedBody, name: str, content: str, position: str = "end") -> ParsedBody:
    if name == _PREAMBLE:
        raise SectionExists(_PREAMBLE)
    if any(section.name == name for section in parsed.sections):
        raise SectionExists(name)
    sections = list(parsed.sections)
    section = Section(name=name, heading=f"## {name}\n", content=str(content))
    index = _position_index(parsed, position)
    sections.insert(index, section)
    return parse(parsed.preamble + "".join(item.raw for item in sections))


def remove_section(parsed: ParsedBody, name: str) -> ParsedBody:
    if name == _PREAMBLE:
        return parse("".join(section.raw for section in parsed.sections))
    index = _section_index(parsed, name)
    sections = list(parsed.sections)
    del sections[index]
    return parse(parsed.preamble + "".join(section.raw for section in sections))


def rename_section(parsed: ParsedBody, old_name: str, new_name: str) -> ParsedBody:
    if old_name == _PREAMBLE or new_name == _PREAMBLE:
        raise InvalidPosition("_preamble cannot be renamed")
    index = _section_index(parsed, old_name)
    if any(section.name == new_name for section in parsed.sections):
        raise SectionExists(new_name)
    sections = list(parsed.sections)
    ending = "" if sections[index].heading.endswith("\n") else "\n"
    sections[index] = replace(sections[index], name=new_name, heading=f"## {new_name}{ending}")
    return parse(parsed.preamble + "".join(section.raw for section in sections))


def reorder(parsed: ParsedBody, names: list[str]) -> ParsedBody:
    current = [section.name for section in parsed.sections]
    if sorted(names) != sorted(current) or len(names) != len(current):
        missing = next((name for name in current if name not in names), None)
        raise SectionNotFound(missing or "section")
    by_name = {section.name: section for section in parsed.sections}
    return parse(parsed.preamble + "".join(by_name[name].raw for name in names))


def compute_diff(before: str, after: str) -> str:
    return "".join(
        difflib.unified_diff(
            before.splitlines(keepends=True),
            after.splitlines(keepends=True),
            fromfile="before",
            tofile="after",
            n=3,
        )
    )


def diffs_equivalent(left: str, right: str) -> bool:
    return _normalize_diff(left) == _normalize_diff(right)


def _section_boundaries(text: str) -> list[tuple[int, int, str, str]]:
    boundaries: list[tuple[int, int, str, str]] = []
    offset = 0
    fence: str | None = None
    for line in text.splitlines(keepends=True):
        stripped = line.strip()
        if fence:
            if stripped.startswith(fence):
                fence = None
        else:
            fence_match = _FENCE_RE.match(line)
            if fence_match:
                fence = fence_match.group(1)
            else:
                heading_text = line[:-1] if line.endswith("\n") else line
                if heading_text.endswith("\r"):
                    heading_text = heading_text[:-1]
                match = HEADING_RE.match(heading_text)
                if match:
                    boundaries.append((offset, offset + len(line), match.group(1), line))
        offset += len(line)
    return boundaries


def _extract_title(preamble: str) -> str | None:
    for line in preamble.splitlines():
        match = TITLE_RE.match(line)
        if match:
            return match.group(1).strip() or None
    return None


def _extract_goal(sections: list[Section]) -> str | None:
    for section in sections:
        if section.name == "Goal":
            paragraphs = re.split(r"\n\s*\n", section.content.strip())
            if paragraphs and paragraphs[0].strip():
                return " ".join(line.strip() for line in paragraphs[0].splitlines()).strip() or None
            return None
    return None


def _section_index(parsed: ParsedBody, name: str) -> int:
    for index, section in enumerate(parsed.sections):
        if section.name == name:
            return index
    raise SectionNotFound(name)


def _position_index(parsed: ParsedBody, position: str) -> int:
    if position == "start":
        return 0
    if position == "end":
        return len(parsed.sections)
    if position.startswith("after:"):
        return _section_index(parsed, position.removeprefix("after:")) + 1
    if position.startswith("before:"):
        return _section_index(parsed, position.removeprefix("before:"))
    raise InvalidPosition(position)


def _line_count(text: str) -> int:
    return len(text.splitlines()) if text else 0


def _normalize_diff(value: str) -> str:
    lines = value.replace("\r\n", "\n").split("\n")
    lines = [line.rstrip() for line in lines]
    while lines and lines[-1] == "":
        lines.pop()
    return "\n".join(lines)

"""Supabase/Postgres Store adapter for resident mode."""

from __future__ import annotations

from contextlib import contextmanager
from datetime import UTC, datetime
import os
from typing import Any, Iterator, Sequence
from uuid import uuid4
JSONDict = dict[str, Any]

_JSON_COLUMNS = {"arguments", "details", "error_details", "in_burst_with", "prompt_snapshot", "provider_response_summary", "request_body", "request_summary", "result", "state_at_turn", "transcription_metadata", "triggered_by_message_ids", "warnings_issued"}


class SupabaseStore:
    def __init__(self, dsn: str | None = None, *, connection: Any = None) -> None:
        if connection is None:
            dsn = dsn or os.environ["SUPABASE_DB_URL"]
            self._conn = _connect(dsn)
            self._owns_connection = True
        else:
            self._conn = connection
            self._owns_connection = False
        self._transaction_depth = 0

    @classmethod
    def from_env(cls) -> "SupabaseStore":
        return cls(os.environ["SUPABASE_DB_URL"])

    def close(self) -> None:
        if self._owns_connection:
            self._conn.close()

    @contextmanager
    def transaction(self) -> Iterator[None]:
        self._transaction_depth += 1
        try:
            with self._conn.transaction():
                yield
        finally:
            self._transaction_depth -= 1

    def create_message(
        self,
        *,
        epic_id: str | None,
        direction: str,
        content: str,
        discord_message_id: str | None = None,
        bot_turn_id: str | None = None,
        has_code_attachment: bool = False,
        has_image_attachment: bool = False,
        in_burst_with: Sequence[str] | None = None,
        was_voice_message: bool = False,
        audio_storage_url: str | None = None,
        transcription_metadata: JSONDict | None = None,
        synthesize_outbound_id: bool = True,
    ) -> JSONDict:
        message_id = _new_id("msg")
        if (
            synthesize_outbound_id
            and direction == "outbound"
            and discord_message_id is None
            and bot_turn_id
        ):
            discord_message_id = self._next_invocation_message_id(bot_turn_id)
        self._conn.execute(
            "INSERT INTO messages (id, epic_id, direction, content, discord_message_id, has_code_attachment, has_image_attachment, in_burst_with, was_voice_message, audio_storage_url, transcription_metadata, bot_turn_id) VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s)",
            (
                message_id,
                epic_id,
                direction,
                content,
                discord_message_id,
                has_code_attachment,
                has_image_attachment,
                _json(list(in_burst_with)) if in_burst_with else None,
                was_voice_message,
                audio_storage_url,
                _json(transcription_metadata) if transcription_metadata else None,
                bot_turn_id,
            ),
        )
        return self.load_message(message_id) or {}

    def load_message(self, message_id: str) -> JSONDict | None:
        return _normalize(self._conn.execute("SELECT * FROM messages WHERE id = %s", (message_id,)).fetchone())

    def load_messages(self, message_ids: Sequence[str]) -> list[JSONDict]:
        if not message_ids:
            return []
        rows = self._conn.execute(
            "SELECT * FROM messages WHERE id = ANY(%s)",
            (list(message_ids),),
        ).fetchall()
        by_id = {row["id"]: _normalize(row) for row in rows}
        return [by_id[item] for item in message_ids if item in by_id]

    def update_message(self, message_id: str, **changes: Any) -> JSONDict:
        return self._update("messages", "id", message_id, changes, _MESSAGE_COLUMNS, self.load_message)

    def create_turn(
        self,
        *,
        epic_id: str,
        triggered_by_message_ids: Sequence[str],
        prompt_snapshot: JSONDict | None = None,
        prompt_version: str | None = None,
        state_at_turn: JSONDict | None = None,
        model_version: str | None = None,
    ) -> JSONDict:
        turn_id = _new_id("turn")
        self._conn.execute(
            "INSERT INTO bot_turns (id, epic_id, triggered_by_message_ids, prompt_snapshot, prompt_version, status, state_at_turn, model_version) VALUES (%s, %s, %s, %s, %s, 'in_progress', %s, %s)",
            (
                turn_id,
                epic_id,
                _json(list(triggered_by_message_ids)),
                _json(prompt_snapshot) if prompt_snapshot is not None else None,
                prompt_version,
                _json(state_at_turn) if state_at_turn is not None else None,
                model_version,
            ),
        )
        return self._load_turn(turn_id) or {}

    def update_turn(self, turn_id: str, **changes: Any) -> JSONDict:
        if changes.get("status") in {"completed", "failed", "abandoned"} and "completed_at" not in changes:
            changes = {**changes, "completed_at": datetime.now(UTC)}
        return self._update("bot_turns", "id", turn_id, changes, _TURN_COLUMNS, self._load_turn)

    def find_abandoned_turns(self, older_than_seconds: int) -> list[JSONDict]:
        return _normalize_rows(
            self._conn.execute(
                "SELECT * FROM bot_turns WHERE status = 'in_progress' AND started_at <= now() - (%s * interval '1 second') ORDER BY started_at",
                (older_than_seconds,),
            ).fetchall()
        )

    def record_tool_call(
        self,
        *,
        turn_id: str,
        tool_name: str,
        operation_kind: str,
        arguments: JSONDict,
        result: JSONDict,
        duration_ms: int,
    ) -> JSONDict:
        tool_call_id = _new_id("tool")
        self._conn.execute(
            "INSERT INTO tool_calls (id, turn_id, tool_name, operation_kind, arguments, result, duration_ms) VALUES (%s, %s, %s, %s, %s, %s, %s)",
            (tool_call_id, turn_id, tool_name, operation_kind, _json(arguments), _json(result), duration_ms),
        )
        return self._load_tool_call(tool_call_id) or {}

    def log_system_event(
        self,
        *,
        level: str,
        category: str,
        event_type: str,
        message: str,
        details: JSONDict | None = None,
        turn_id: str | None = None,
        epic_id: str | None = None,
    ) -> JSONDict:
        log_id = _new_id("log")
        self._conn.execute(
            "INSERT INTO system_logs (id, level, category, event_type, message, details, turn_id, epic_id) VALUES (%s, %s, %s, %s, %s, %s, %s, %s)",
            (log_id, level, category, event_type, message, _json(details or {}), turn_id, epic_id),
        )
        return self._load_system_log(log_id) or {}

    def acquire_epic_lock(self, epic_id: str, *, holder_id: str, timeout_seconds: int = 60) -> bool:
        row = self._conn.execute(
            "INSERT INTO epic_locks (epic_id, holder_id, acquired_at, expires_at) VALUES (%s, %s, now(), now() + (%s * interval '1 second')) ON CONFLICT (epic_id) DO UPDATE SET holder_id = EXCLUDED.holder_id, acquired_at = now(), expires_at = EXCLUDED.expires_at WHERE epic_locks.expires_at <= now() OR epic_locks.holder_id = EXCLUDED.holder_id RETURNING holder_id",
            (epic_id, holder_id, timeout_seconds),
        ).fetchone()
        return bool(row and row["holder_id"] == holder_id)

    def release_epic_lock(self, epic_id: str, *, holder_id: str) -> None:
        self._conn.execute(
            "DELETE FROM epic_locks WHERE epic_id = %s AND holder_id = %s",
            (epic_id, holder_id),
        )

    def load_hot_context(self, epic_id: str) -> JSONDict:
        epic = _normalize(self._conn.execute("SELECT * FROM epics WHERE id = %s", (epic_id,)).fetchone())
        messages = _normalize_rows(
            self._conn.execute(
                "SELECT * FROM messages WHERE epic_id = %s ORDER BY sent_at DESC LIMIT 10",
                (epic_id,),
            ).fetchall()
        )
        tool_calls = _normalize_rows(
            self._conn.execute(
                "SELECT tool_calls.* FROM tool_calls JOIN bot_turns ON bot_turns.id = tool_calls.turn_id WHERE bot_turns.epic_id = %s ORDER BY tool_calls.called_at DESC LIMIT 10",
                (epic_id,),
            ).fetchall()
        )
        return {"epic": epic, "recent_messages": list(reversed(messages)), "recent_tool_calls": list(reversed(tool_calls))}

    def find_unprocessed_messages(self, epic_id: str, started_at: str, exclude_ids: Sequence[str]) -> list[JSONDict]:
        return _normalize_rows(
            self._conn.execute(
                "SELECT * FROM messages WHERE epic_id = %s AND direction = 'inbound' AND sent_at >= %s AND NOT (id = ANY(%s)) ORDER BY sent_at, id",
                (epic_id, started_at, list(exclude_ids)),
            ).fetchall()
        )

    def insert_pending(
        self,
        *,
        idempotency_key: str,
        provider: str,
        endpoint: str,
        request_summary: JSONDict,
        request_body: JSONDict | None = None,
        turn_id: str | None = None,
        tool_call_id: str | None = None,
    ) -> JSONDict:
        request_id = _new_id("ext")
        self._conn.execute(
            "INSERT INTO external_requests (id, idempotency_key, provider, endpoint, tool_call_id, turn_id, request_summary, request_body, status) VALUES (%s, %s, %s, %s, %s, %s, %s, %s, 'pending')",
