        unknown = set(changes) - allowed
        if unknown:
            raise ValueError(f"unsupported {table} columns: {', '.join(sorted(unknown))}")
        assignments = ", ".join(f"{key} = %s" for key in changes)
        values = [_to_sql_value(key, value) for key, value in changes.items()]
        self._conn.execute(
