    )


def _event_from_tool_call(
    *,
    entry: ToolEntry,
    arguments: JSONDict,
    result: JSONDict,
    tool_call: JSONDict,
    duration_ms: int,
) -> Event:
    text = None
    if entry.event_kind == "activity":
        text = _first_string(
            result.get("description"),
            result.get("text"),
            arguments.get("description"),
            arguments.get("text"),
        )
    return Event(
        ts=_now(),
        kind=entry.event_kind,
        name=entry.name,
        text=text,
        ms=duration_ms,
        tool_call_id=tool_call["id"],
    )


def _normalize_result(value: Any) -> JSONDict:
    if value is None:
        return {}
    if isinstance(value, dict):
        return value
    return {"value": value}


def _first_string(*values: Any) -> str | None:
    for value in values:
        if isinstance(value, str):
            return value
    return None


