"""Invocation-mode result envelope for Arnold turns.

The stable JSON helpers in this module are the only supported serialization
path for envelopes and streamed events. ``serialize_for_diff`` is narrower:
it exists only for CLI-vs-Python envelope equivalence tests and must not be
used for stream-vs-envelope comparisons.
"""

from __future__ import annotations

from dataclasses import asdict, dataclass, field, is_dataclass
import json
from typing import Any, Literal


Outcome = Literal["completed", "blocked_on_caller", "errored", "aborted"]
EventKind = Literal["tool_call", "activity", "turn_start", "turn_end"]


@dataclass(frozen=True)
class EnvelopeError:
    code: str
    message: str
    retryable: bool = False


@dataclass(frozen=True)
class StateDelta:
    body_diff: str = ""
    checklist_changes: list[dict[str, Any]] = field(default_factory=list)
    sprint_changes: list[dict[str, Any]] = field(default_factory=list)
    state_transition: dict[str, Any] | None = None


@dataclass(frozen=True)
class Event:
    ts: str
    kind: EventKind
    name: str | None = None
    text: str | None = None
    ms: int | None = None
    tool_call_id: str | None = None
    started_at: str | None = None
    completed_at: str | None = None
    details: dict[str, Any] = field(default_factory=dict)


@dataclass(frozen=True)
class Envelope:
    turn_id: str
    epic_state_before: str
    epic_state_after: str
    reply: str
    epic_id: str | None = None
    state_delta: StateDelta = field(default_factory=StateDelta)
    questions: list[str] = field(default_factory=list)
    events: list[Event] = field(default_factory=list)
    tool_call_count: int = 0
    outcome: Outcome = "completed"
    error: EnvelopeError | None = None
    envelope_version: str = "1"
    started_at: str | None = None
    completed_at: str | None = None

    def to_dict(self) -> dict[str, Any]:
        return _drop_none(_to_plain(self))

    def to_json(self) -> str:
        return stable_json_dumps(self.to_dict())


def stable_json_dumps(value: Any) -> str:
    """Serialize JSON with byte-stable ordering and compact separators."""

    return json.dumps(
        _drop_none(_to_plain(value)),
        sort_keys=True,
        separators=(",", ":"),
        ensure_ascii=False,
    )


def event_to_json(event: Event) -> str:
    return stable_json_dumps(event)


def serialize_for_diff(envelope: Envelope | dict[str, Any]) -> str:
    """Return a byte-stable comparison form for CLI-vs-Python tests only.

    This strips the non-deterministic fields called out by the Subagent
    Contract: envelope ``reply``, event ``text``, and ``started_at`` /
    ``completed_at`` timestamps wherever they appear. Streaming tests must
    compare real events, not this projection.
    """

    data = _drop_none(_to_plain(envelope))
    return stable_json_dumps(_strip_diff_nondeterminism(data))


def _to_plain(value: Any) -> Any:
    if is_dataclass(value):
        return asdict(value)
    if isinstance(value, dict):
        return {key: _to_plain(item) for key, item in value.items()}
    if isinstance(value, list):
        return [_to_plain(item) for item in value]
    if isinstance(value, tuple):
        return [_to_plain(item) for item in value]
    return value


def _drop_none(value: Any) -> Any:
    if isinstance(value, dict):
        return {
            key: _drop_none(item)
            for key, item in value.items()
            if item is not None
        }
    if isinstance(value, list):
        return [_drop_none(item) for item in value]
    return value


def _strip_diff_nondeterminism(value: Any) -> Any:
    if isinstance(value, dict):
        return {
            key: _strip_diff_nondeterminism(item)
            for key, item in value.items()
            if key not in {"reply", "text", "started_at", "completed_at"}
        }
    if isinstance(value, list):
        return [_strip_diff_nondeterminism(item) for item in value]
    return value

"""Deterministic fake model adapter for offline tests."""

from __future__ import annotations

from dataclasses import dataclass
import random
from typing import Any, Iterable, Sequence

from agent_kit.ports import (
    JSONDict,
    ModelTurnResult,
    ProviderError,
    ToolRequest,
)


ScriptItem = ModelTurnResult | JSONDict | BaseException


@dataclass(frozen=True)
class FakeModelStep:
    final_text: str | None = None
    tool_requests: tuple[ToolRequest, ...] = ()
    reasoning: str | None = None
    provider_request_id: str | None = None
    response_summary: JSONDict | None = None

    def to_result(self) -> ModelTurnResult:
        return ModelTurnResult(
            final_text=self.final_text,
            tool_requests=list(self.tool_requests),
            reasoning=self.reasoning,
            provider_request_id=self.provider_request_id,
            response_summary=self.response_summary,
        )


class FakeModel:
    def __init__(
        self,
        *,
        seed: int | str = 0,
        script: Iterable[ScriptItem] | None = None,
    ) -> None:
        self.seed = seed
        self._random = random.Random(str(seed))
        self._script = list(script) if script is not None else None
        self.calls: list[JSONDict] = []
        self.call_count = 0

    def complete_turn(
        self,
        *,
        model_id: str,
        messages: Sequence[JSONDict],
        tools: Sequence[JSONDict],
        hot_context: JSONDict,
        idempotency_key: str | None = None,
    ) -> ModelTurnResult:
        self.call_count += 1
        self.calls.append(
            {
                "model_id": model_id,
                "messages": list(messages),
                "tools": list(tools),
                "hot_context": hot_context,
                "idempotency_key": idempotency_key,
            }
        )
        if self._script is None:
            return ModelTurnResult(
                final_text=f"fake reply {self._random.randint(1000, 9999)}",
                reasoning="fake deterministic final response",
                provider_request_id=f"fake_req_{self.call_count}",
                response_summary={"kind": "final"},
            )
        if self.call_count > len(self._script):
            return ModelTurnResult(
                final_text="",
                reasoning="fake script exhausted",
                provider_request_id=f"fake_req_{self.call_count}",
                response_summary={"kind": "exhausted"},
            )
        return _coerce_script_item(
            self._script[self.call_count - 1],
            call_count=self.call_count,
        )


def tool_request(name: str, arguments: JSONDict | None = None) -> ToolRequest:
    return ToolRequest(name=name, arguments=arguments or {})


def provider_error(
    error_details: JSONDict | None = None,
    provider_request_id: str | None = None,
) -> ProviderError:
    return ProviderError(
        error_details=error_details or {"code": "fake_provider_error"},
        provider_request_id=provider_request_id,
    )


def _coerce_script_item(item: ScriptItem, *, call_count: int) -> ModelTurnResult:
    if isinstance(item, BaseException):
        raise item
    if isinstance(item, ModelTurnResult):
        return item
    if isinstance(item, FakeModelStep):
        return item.to_result()
    if isinstance(item, dict):
        if "exception" in item:
            exception = item["exception"]
            if isinstance(exception, BaseException):
                raise exception
            raise RuntimeError(str(exception))
        if item.get("provider_error"):
            raise provider_error(
                item.get("error_details"),
                item.get("provider_request_id"),
            )
        if item.get("runtime_error"):
            raise RuntimeError(str(item.get("runtime_error")))
        return ModelTurnResult(
            final_text=item.get("final_text"),
            tool_requests=[
                _coerce_tool_request(tool)
                for tool in item.get("tool_requests", [])
            ],
            reasoning=item.get("reasoning"),
            provider_request_id=item.get(
                "provider_request_id",
                f"fake_req_{call_count}",
            ),
            response_summary=item.get("response_summary"),
        )
    raise TypeError(f"Unsupported fake model script item: {type(item)!r}")


def _coerce_tool_request(value: Any) -> ToolRequest:
    if isinstance(value, ToolRequest):
        return value
    if isinstance(value, dict):
        return ToolRequest(
            name=value["name"],
            arguments=value.get("arguments", {}),
        )
    raise TypeError(f"Unsupported tool request: {type(value)!r}")


